// ---- Improved School ERP Outreach - Spam Reduced v2 ----
const schoolName = $json['School Name'] || 'Your School';
const email = $json.Email;
const address = $json.Address || '';

let city = 'Karimnagar';
if (address) {
  const parts = address.split(',').map(p => p.trim()).filter(Boolean);
  if (parts.length > 0) {
    city = parts[parts.length - 1];
  }
}

const coachingRaw = ($json['IIT/NEET Foundation/Coaching'] || '').toString().trim().toLowerCase();
const hasCoaching = (coachingRaw && coachingRaw !== 'not mentioned' && coachingRaw !== 'no');

const subject = `School Management System for ${schoolName}`;

// Plain Text Version (Very important for deliverability)
let emailText = `Dear Principal / Management Team at ${schoolName}, ${city}

I hope this message finds you well.

My name is Rishi Ananthula. I develop School Management ERP software for schools like yours.

The system offers:
- Teachers: attendance, timetable, assignments, and marks entry
- Parents: real-time updates, fee payments, and progress tracking
- Students: results, homework, notices, and schedule
- Management: admin panel, staff & fee management, and analytics
- Notifications: alerts via mobile app

${hasCoaching ? '- IIT/NEET foundation performance tracking\n' : ''}

It is available on Android, iOS, and Web with regular updates and support.

If you feel this could be useful for ${schoolName}, I would be happy to arrange a short demo at your convenience.

You can reply to this email or reach me at rishiananthula0@gmail.com.

Best regards,
Rishi Ananthula
Mobile & Web App Developer
School ERP Solutions

Phone/WhatsApp: [Your Number Here]
LinkedIn: https://www.linkedin.com/in/rishi-ananthula-88866232a

---
This is a one-time outreach email. If you do not wish to receive further messages, simply reply with "unsubscribe" and I will remove you immediately.
Sent from: Hyderabad, Telangana, India`;

// HTML Version - Clean, professional, no buttons, minimal styling
let emailBody = `
<html>
<body style="font-family: Arial, sans-serif; line-height: 1.6; color: #333; max-width: 600px; margin: 0 auto;">
  <p>Dear Principal / Management Team at <strong>${schoolName}</strong>, ${city}</p>

  <p>I hope this message finds you well.</p>

  <p>My name is Rishi Ananthula. I develop School Management ERP software for schools like yours.</p>

  <p><strong>Key features include:</strong></p>
  <ul>
    <li><strong>Teachers:</strong> attendance, timetable, assignments, and marks entry</li>
    <li><strong>Parents:</strong> real-time updates, fee payments, and progress tracking</li>
    <li><strong>Students:</strong> results, homework, notices, and schedule</li>
    <li><strong>Management:</strong> admin panel, staff & fee management, analytics</li>
    <li><strong>Notifications:</strong> automated alerts to parents and students</li>
    ${hasCoaching ? '<li><strong>IIT/NEET Tracking:</strong> performance analytics and mock test results</li>' : ''}
  </ul>

  <p>Available on Android, iOS, and Web with ongoing support.</p>

  <p>If this solution might help ${schoolName}, I would be glad to arrange a short, no-obligation demo. Please feel free to reply to this email or contact me directly.</p>

  <p>Best regards,<br>
  <strong>Rishi Ananthula</strong><br>
  Mobile & Web App Developer<br>
  School ERP Solutions</p>

  <hr style="border: none; border-top: 1px solid #eee; margin: 25px 0;">

  <p style="font-size: 12px; color: #666;">
    This is a one-time outreach email regarding school management software.<br>
    If you do not wish to receive any further emails, simply reply with the word <strong>"unsubscribe"</strong> and I will remove your school from my list immediately.<br><br>
    Sent from: Hyderabad, Telangana, India
  </p>
</body>
</html>
`;

return {
  json: {
    ...$json,
    emailBody: emailBody.trim(),
    emailText: emailText,
    subject: subject,
    Status: 'Sent'
  }
};
